import {useState} from 'react'

const App = () => {
 const [counter, setCounter] = useState(0);

 const increment = () => {
  setCounter(counter + 1)
 }

 return (
  &lt;>
   &lt;h1>{counter}&lt;/h1>
   &lt;button onClick={increment}>Inkrement&lt;/button>
  &lt;/>
 )
}

export default App
